const scenarios = {
  db_overload: { cpu_usage: 95, memory_usage: 88, api_latency_ms: 5000, error_rate: 0.25 },
  api_timeout: { cpu_usage: 45, memory_usage: 60, api_latency_ms: 30000, error_rate: 0.80 },
