  server_crash: { cpu_usage: 0, memory_usage: 0, api_latency_ms: 0, error_rate: 1.0 }
};

const scenario = $input.item.json.body.scenario || "db_overload";
const service = $input.item.json.body.target_service || "checkout-api";
const metrics = scenarios[scenario] || scenarios.db_overload;

return [{
  json: {
    timestamp: new Date().toISOString(),
    source: "chaos_engineering",
    service: service,
    scenario: scenario,
    ...metrics,
    environment: "staging",
    simulated: true
  }
}];

