return [{
  json: {
    repository: deployment.name,
    deployed_at: deployment.pushed_at,
    time_window_start: new Date(deploymentTime.getTime() - timeWindow).toISOString(),
    time_window_end: new Date(deploymentTime.getTime() + timeWindow).toISOString(),
    correlation_query: `SELECT * FROM incidents WHERE service = '${deployment.name}' AND detected_at BETWEEN '${new Date(deploymentTime.getTime() - timeWindow).toISOString()}' AND '${new Date(deploymentTime.getTime() + timeWindow).toISOString()}'`
  }
}];

