parameters.jsCode:
const incident = $input.first().json;
const detectedTime = new Date(incident.detected_at);
const resolvedTime = new Date(incident.resolved_at);
const duration = (resolvedTime - detectedTime) / 1000;

return [{
  json: {
    incident_id: incident.id,
    service: incident.service,
    severity: incident.severity,
    timeline: {
      detection: incident.detected_at,
      resolution: incident.resolved_at,
      duration_seconds: duration,
      mttr: Math.round(duration / 60) + " minutes"
    },
    root_cause: incident.root_cause,
    remediation: incident.remediation_result,
    replay_url: `https://dashboard.company.com/replay/${incident.id}`
  }
}];

