return [
  { json: { action: "queue_low_priority", queue: "mes:low_priority_queue", ttl: 600 } },
  { json: { action: "protect_critical_apis", endpoints: ["cycle_complete", "ng_detection", "plc_data"], max_rate: 50 } },
  { json: { action: "enable_circuit_breaker", services: ["video_recorder", "analytics_engine"], threshold: 0.5 } }
];

const processes = [
  { name: "uvicorn", port: 8000, last_data_timestamp: Date.now() - 120000 },
  { name: "flask_cms", port: 5000, last_data_timestamp: Date.now() - 30000 },
  { name: "ffmpeg_recorder", pid: 1234, last_data_timestamp: Date.now() - 300000 },
  { name: "rtsp_stream_1", url: "rtsp://camera1", last_frame_timestamp: Date.now() - 400000 },
  { name: "postgres", port: 5432, connection_count: 95 },
  { name: "redis", port: 6379, memory_usage: 85 }
];

const stalled = processes.filter(p => {
  if (p.last_data_timestamp && (Date.now() - p.last_data_timestamp) > 180000) return true;
  if (p.last_frame_timestamp && (Date.now() - p.last_frame_timestamp) > 180000) return true;
  return false;
});

return stalled.map(p => ({ json: { ...p, status: "stalled", detected_at: new Date().toISOString() } }));

